var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"이렇게 뵙게 되어 반갑습니다, 스펜서 씨.","JPN":"はじめまして、お会いできて光栄です、スペンサーさん。","ENG":"Pleased to meet you, Ms. Spencer.","TWN":"很高興認識你，史賓瑟女士。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"의외네. 나한테 의뢰를 맡기고 싶어하는 게 관리국인 줄은 몰랐는데.","JPN":"意外ね。依頼主がまさか管理局だったとは。","ENG":"Huh. I didn't expect the Administration to have a job for me.","TWN":"真是意外。沒想到是管理局委託我辦事。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"리프터의 직업수명은 짧아요. 당신만큼 수없이 대균열을 오가며 식견을 쌓은 프로는 더더욱 드물죠.","JPN":"ただでさえリフターの現役期間は短い。あなたほどの大亀裂に出入りした経験が豊富なベテランとなると、さらに限られる。","ENG":"Lifters have short lifespans. And professionals who have extensive experience traveling the Grand Dimension Crevice like you are even rarer.","TWN":"打撈人這行的職業生涯都十分短暫。像你這樣，多次來回大峽谷，經驗豐富的打撈人，更是少之又少。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"관리국의 예절과 관용은 남다르네. 우리 같은 한탕주의자를 무려 직업으로 취급해 주다니.","JPN":"管理局は相変わらず律儀で懐が深いな。私たちみたいな一攫千金狙いを正当に認めてくれるなんて。","ENG":"You Administration folks have great tolerance. Treating us gamblers like real professionals.","TWN":"管理局的禮儀和格局真是非同一般啊。居然把我們這樣的投機分子，也當作正經八百的職業來看待。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"챔버에선 기술력이 곧 지위입니다. 지위가 있으면 그에 합당한 대우를 받는 게 당연하죠.","JPN":"チェンバーは実力主義なんです。実力があればそれ相応の地位と待遇を受けるのは当然のことです。","ENG":"In Chamber, skill equates to status. And if you have status, it's only natural to receive treatment accordingly.","TWN":"在強巴，技術就是地位。有了地位，自然會得到應有的待遇。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"그게 설령 불법 다이브를 일삼는 범죄자라 해도, 논외는 아닙니다.","JPN":"たとえ違法ダイブを平然と繰り返す犯罪者であってもです。","ENG":"Even if that person is someone who engages in illegal dives, it won't be an issue.","TWN":"即使是非法躍入的犯罪分子，也不例外。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"단도직입적으로 묻지.","JPN":"単刀直入に聞く。","ENG":"I’ll cut to the chase.","TWN":"那我也不廢話了。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"원하는 게 뭐야?","JPN":"何を望んでいる？","ENG":"What do you want?","TWN":"你們想要什麼？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"3개월 전, 누군가 챔버 대균열 심층에 진입했습니다. 리프터들 사이에선 <color=#ffd34c>5층</color>이라 불리는 곳이죠.","JPN":"3カ月前、何者かによるチェンバー大亀裂の深層部への侵入がありました。リフターの間では<color=#ffd34c>5階</color>と呼ばれる場所です。","ENG":"Three months ago, someone infiltrated the depths of Chamber's Grand Dimension Crevice. Lifters call it the <color=#ffd34c>5th floor</color>.","TWN":"三個月前，有人進入了強巴大峽谷深處。那個被打撈人稱為<color=#ffd34c>地下5層</color>的地方。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"스펜서, 당신이 그곳에 들어간 침입자를 찾아줬으면 해요.","JPN":"スペンサーさん、あなたにはその侵入者を見つけていただきたい。","ENG":"Ms. Spencer, we want you to find the intruder who entered that place.","TWN":"史賓瑟女士，我們需要你找到闖入那裡的入侵者。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"침입자?","JPN":"侵入者？","ENG":"Intruder?","TWN":"入侵者？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"당신들이 말하는 침입자는 우리 같은 리프터와 뭐가 다르길래 현상금까지 걸지?","JPN":"その侵入者に懸賞金までかけるなんて、私たちリフターとは何が違うんだ？","ENG":"And how is this intruder so different from us lifters that you need to put out a bounty?","TWN":"你說的這些入侵者和我們這樣的打撈人有什麼不同，還要懸賞他們？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"알고 계시겠지만 이면세계의 아티팩트를 현실로 반출하는 건 불법입니다. 아티팩트의 존재가 현실에 끼치는 악영향 때문이죠.","JPN":"ご存知だと思いますが、裏世界のアーティファクトを現実に持ち出すのは違法行為です。アーティファクトが現実世界に及ぼす悪影響を懸念してのものなんです。","ENG":"As you may be aware, bringing Artifacts from the Counterside to the Normalside is illegal because the Artifacts can cause harmful effects to the Normalside.","TWN":"如你所知，將異界的人造神器帶入現實是違法的。這是因為人造神器的存在對現實造成了負面影響。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"그 침입자가 노리고 있는 아티팩트의 규격은 다른 케이스와 급이 달라요. 그걸 현실로 가져오는 순간 돌이킬 수 없게 될 겁니다.","JPN":"その侵入者が手に入れようとしているアーティファクトは、他のものとは格が違います。もしそれが現実世界に持ち込まれたら、取り返しのつかないことになってしまうでしょう。","ENG":"The specs of the Artifact that the intruder is targeting are on another level. Once brought into the Normalside, it will be irreversible.","TWN":"入侵者盯上的人造神器之規格遠超普通水準。一旦將其帶入現實，就沒有挽回的餘地了。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"적어도 당신들은 5층에 그런 위험한 아티팩트가 있다는 걸 알고 있었단 거네.","JPN":"つまり、少なくともあなたちはそんな危険なアーティファクトが5階に眠っているということを知っていたということだな。","ENG":"So the Administration knew that a dangerous Artifact like that existed on the 5th floor, eh?","TWN":"最起碼你們知道地下五層有那種危險的人造神器。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"대정화전쟁 이후, 챔버 대균열은 이면세계를 개척하려는 기업들의 탐사가 가장 활발했던 곳입니다.","JPN":"大浄化戦争の終戦後、チェンバー大亀裂は裏世界の開拓を目指す企業たちによる探査が最も盛んに行われていた場所です。","ENG":"After the Great Purification War, the Chamber's Grand Dimension Crevice was the most active place for corporations trying to map out the Counterside.","TWN":"淨化之戰後，強巴的大峽谷是各勢力探索異界最為活躍的地方。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"기업이 가진 정보는 모두 관리국에게도 공유되고 있으니까요.","JPN":"企業の持つ情報は、全て管理局にも共有されていますからね。","ENG":"And all information held by corporations is also shared with the Administration.","TWN":"而公司持有的所有資訊也與管理局共用。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"침입자가 5층으로 향한 게 3개월 전이라면 진작에 죽었어.","JPN":"その侵入者が5階に向かってから、もう3カ月も経っているなら間違いなく死んでいる。","ENG":"If this intruder headed to the 5th floor three months ago, he's long dead by now.","TWN":"如果入侵者三個月前去了地下五層，那他早就死了。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"살아있을 겁니다. 그자가 무사히 그 아티팩트를 손에 넣었다면 말이죠.","JPN":"いいえ、生きています。もしその者が、問題なく例のアーティファクトを手に入れたのなら。","ENG":"He'll be alive. If he managed to obtain the Artifact he was looking for, that is.","TWN":"他們可能還活著。如果順利地拿到人造神器的話。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"뭐…?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그건 또 무슨 소리지? 아티팩트가 무슨 부활장치라도 되나?","JPN":"それはいったいどういうことだ？　アーティファクトが復活装置にでもなるってことか？","ENG":"What does that mean? Is this Artifact some kind of resurrection device?","TWN":"這是什麼意思？人造神器是某種復活裝置嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"죄송합니다. 이 이상은 관리국 기밀사항이라서요.","JPN":"申し訳ございません。これ以上は管理局の機密事項になります。","ENG":"I apologize. Anything beyond this is classified information.","TWN":"對不起。這是管理局的機密資訊。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"이건 관리국과의 협업을 비밀로 한다는 계약서와 저희가 제공하는 선수금입니다.","JPN":"これは管理局との協業と他言厳禁を条件とする契約書と前払い金です。","ENG":"This is a contract stating that you will be keeping your involvement with the Administration confidential, along with the advance payment for this request.","TWN":"這是與管理局合作的保密協定，以及我們預付的費用。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이 정도면 목숨이랑 맞바꿀만한 금액이네.","JPN":"確かに、これだけの金額なら命以上の価値があるな。","ENG":"This is enough money to trade my life in for.","TWN":"這筆錢夠買我幾條命了。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"나보다 앞서간 양반들도 남부럽지 않게 챙겼겠어.","JPN":"先に依頼した者たちにも、相当な額を支払っているのだろう？","ENG":"Were the poor saps who went ahead of me paid this handsomely as well?","TWN":"那些在我之前的人也能拿這麼多嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"그들은 당신에게 제시한 선수금의 반의 반도 미치지 않는 금액에 의뢰를 승낙했습니다.","JPN":"彼らはあなたへの前払い金の2割以下で承諾してくださっています。","ENG":"They accepted the job at a fraction of the amount we're offering you.","TWN":"他們的報酬不到你預付費用的一半。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"관리국이 당신에게 걸고 있는 기대는 차원이 다르거든요.","JPN":"管理局はあなたにそれだけ大きな期待をかけているのですよ。","ENG":"The expectations the Administration is placing on you are on a different level.","TWN":"管理局對你十分期待。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"음지에서 활동하는 날 관리국에서 인정하고 계시다니, 그것 참 영광이긴 한데.","JPN":"社会の暗部で働く私を管理局が認めていたなんて、それは光栄だけど。","ENG":"It's an honor for someone working in my line of work to be recognized by the Administration.","TWN":"呵呵，走在暗處的我能得到管理局的認可，真是一種榮幸。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};